/**
 * Typed `postMessage` payloads exchanged between the service worker and the
 * main thread. Story 133 / design_log #135.
 *
 * Lifted from the spirit of the section `EVENTS` pattern (see
 * `pwa/src/components/health/health-events.ts` and design_log #134), but
 * adapted for `postMessage`: no `CustomEvent`, no `bubbles`/`composed`, no
 * `HTMLElementEventMap` augmentation — payloads are plain serializable
 * objects whose shape is locked at compile time via the discriminated union.
 *
 * Adding a new SW message:
 *   1. Add a constant to `SW_MESSAGES`.
 *   2. Add the detail type to `SwMessageMap`.
 *   3. Add a `createXxxMessage(...)` factory.
 *   4. Add a `XxxMessage` type alias.
 *   5. Add a handler case in `sw-message-bridge.ts`'s switch.
 * Step 5 is enforced at compile time by the `never` exhaustiveness check.
 */

export const SW_MESSAGES = {
    SNAPSHOT_MARK_DIRTY: 'snapshot:mark-dirty',
    SNAPSHOT_REFRESH: 'snapshot:refresh',
    NOTIFICATION_CLICK: 'notification:click',
} as const;

export interface SwMessageMap {
    [SW_MESSAGES.SNAPSHOT_MARK_DIRTY]: undefined;
    [SW_MESSAGES.SNAPSHOT_REFRESH]: undefined;
    [SW_MESSAGES.NOTIFICATION_CLICK]: { path: string };
}

export type SwMessageAction = keyof SwMessageMap;

export type SwMessage<K extends SwMessageAction = SwMessageAction> =
    K extends any ? { action: K; detail: SwMessageMap[K] } : never;

export type SnapshotMarkDirtyMessage = SwMessage<typeof SW_MESSAGES.SNAPSHOT_MARK_DIRTY>;
export type SnapshotRefreshMessage = SwMessage<typeof SW_MESSAGES.SNAPSHOT_REFRESH>;
export type NotificationClickMessage = SwMessage<typeof SW_MESSAGES.NOTIFICATION_CLICK>;

export const createSnapshotMarkDirtyMessage = (): SnapshotMarkDirtyMessage => ({
    action: SW_MESSAGES.SNAPSHOT_MARK_DIRTY,
    detail: undefined,
});

export const createSnapshotRefreshMessage = (): SnapshotRefreshMessage => ({
    action: SW_MESSAGES.SNAPSHOT_REFRESH,
    detail: undefined,
});

export const createNotificationClickMessage = (
    detail: SwMessageMap[typeof SW_MESSAGES.NOTIFICATION_CLICK],
): NotificationClickMessage => ({
    action: SW_MESSAGES.NOTIFICATION_CLICK,
    detail,
});

const KNOWN_ACTIONS = new Set<string>(Object.values(SW_MESSAGES));

/**
 * Runtime type guard for incoming SW messages. The main-thread bridge calls
 * this before switching on `data.action`; anything that doesn't match a
 * known action is ignored silently (could be a stray message from a
 * different SW protocol).
 */
export function isSwMessage(data: unknown): data is SwMessage {
    if (!data || typeof data !== 'object') return false;
    const action = (data as { action?: unknown }).action;
    return typeof action === 'string' && KNOWN_ACTIONS.has(action);
}
